            pos++;
        }
        if (v > 999) return false;
        val = v;
        return true;
    }

 public:
    string processExpression(string inputStr) {
        s = inputStr;
        pos = 0;
        if (s.size() > 10000) return "\"NA\"";
        // 仅允许字母、数字与 +/-
        for (char ch : s) {
            if (!((ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z') ||
                  (ch >= '0' && ch <= '9') || ch == '+' || ch == '-')) {
                return "\"NA\"";
            }
        }
        if (s.empty()) return "\"NA\"";

        int val = 0;
        if (!parseNumber(val)) return "\"NA\"";
        int result = val;

        // 从左到右交替读运算符与操作数
        while (pos < s.size()) {
            char op = s[pos++];
            if (op != '+' && op != '-') return "\"NA\"";
            if (!parseNumber(val)) return "\"NA\"";
            result = (op == '+') ? result + val : result - val;
        }
        if (pos != s.size()) return "\"NA\"";

        // 钳制到 [-255, 255]
        if (result > 255)
            result = 255;
        else if (result < -255)
            result = -255;

        // 对钳制后的值按位取反，再保留低 8 位，输出带双引号
        int out = (~result) & 0xFF;
        char buf[16];
        snprintf(buf, sizeof(buf), "\"0x%02X\"", out);
        return string(buf);
    }
};
