/**
 * P14382 表达式处理 - JavaScript 解答
 * @param {string} inputStr 输入的表达式字符串（不含外层双引号）
 * @return {string} 十六进制结果或 "NA"
 */
var processExpression = function(inputStr) {
    var s = inputStr;
    var n = s.length;

    // 长度检查
    if (n > 10000) return '"NA"';

    // 字符合法性检查：仅允许字母、数字与 +/-
    for (var i = 0; i < n; i++) {
        var c = s.charCodeAt(i);
        var valid = (c >= 48 && c <= 57)
            || (c >= 65 && c <= 90)
            || (c >= 97 && c <= 122)
            || c === 43 || c === 45;
        if (!valid) return '"NA"';
    }

    if (n === 0) return '"NA"';

    var pos = 0;

    // 解析整数：十六进制 / 八进制 / 十进制
    function parseNumber() {
        if (pos >= n) return { ok: false };

        // 0x / 0X 十六进制
        if (s[pos] === '0' && pos + 1 < n && (s[pos + 1] === 'x' || s[pos + 1] === 'X')) {
            pos += 2;
            var v = 0, ok = false;
            while (pos < n) {
                var c = s.charCodeAt(pos), d;
                if (c >= 48 && c <= 57) d = c - 48;
                else if (c >= 97 && c <= 102) d = c - 87;
                else if (c >= 65 && c <= 70) d = c - 55;
                else break;
                ok = true; v = v * 16 + d; pos++;
            }
            if (!ok || v > 999) return { ok: false };
            return { ok: true, val: v };
        }

        // 0o / 0O 八进制（仅 0-7）
        if (s[pos] === '0' && pos + 1 < n && (s[pos + 1] === 'o' || s[pos + 1] === 'O')) {
            pos += 2;
            var v = 0, ok = false;
            while (pos < n && s[pos] >= '0' && s[pos] <= '7') {
                ok = true; v = v * 8 + (s.charCodeAt(pos) - 48); pos++;
            }
            if (!ok || v > 999) return { ok: false };
            return { ok: true, val: v };
        }

        // 十进制
        if (s.charCodeAt(pos) < 48 || s.charCodeAt(pos) > 57) return { ok: false };
        var v = 0;
        while (pos < n && s.charCodeAt(pos) >= 48 && s.charCodeAt(pos) <= 57) {
            v = v * 10 + (s.charCodeAt(pos) - 48); pos++;
        }
        if (v > 999) return { ok: false };
        return { ok: true, val: v };
    }

    var first = parseNumber();
    if (!first.ok) return '"NA"';
    var result = first.val;

    // 从左到右交替读取运算符和操作数
    while (pos < n) {
        var op = s[pos++];
        if (op !== '+' && op !== '-') return '"NA"';
        var num = parseNumber();
        if (!num.ok) return '"NA"';
        result = (op === '+') ? result + num.val : result - num.val;
    }

    if (pos !== n) return '"NA"';

    // 钳制到 [-255, 255]
    if (result > 255) result = 255;
    else if (result < -255) result = -255;

    // 按位取反后保留低 8 位
    var out = (~result) & 0xFF;
    var hex = out.toString(16).toUpperCase();
    if (hex.length < 2) hex = '0' + hex;
    return '"0x' + hex + '"';
};
